#include "TriggerCameraMove.h"
#include "FL_TriggerJson.h"
#include <algorithm>
#include <cstdio>
namespace FLTriggers { TriggerCameraMove::TriggerCameraMove():dontReturnToPlayer_(false){callOnlyOnce_=true;}void TriggerCameraMove::load(const std::string&i,const flrapidjson::Value&j){Trigger::load(i,j);dontReturnToPlayer_=Json::boolean(j,"dontReturnToPlayer");if(j.HasMember("checkpoints")&&j["checkpoints"].IsObject()){const flrapidjson::Value&c=j["checkpoints"];std::vector<std::pair<int,const flrapidjson::Value*> >o;for(flrapidjson::Value::ConstMemberIterator it=c.MemberBegin();it!=c.MemberEnd();++it){int n=0;if(std::sscanf(it->name.GetString(),"point_%d",&n)==1)o.push_back(std::make_pair(n,&it->value));}std::sort(o.begin(),o.end(),[](const std::pair<int,const flrapidjson::Value*>&a,const std::pair<int,const flrapidjson::Value*>&b){return a.first<b.first;});for(size_t n=0;n<o.size();++n){const flrapidjson::Value&v=*o[n].second;points_.push_back(Json::point(v,"position"));durations_.push_back(Json::number(v,"duration"));delays_.push_back(Json::number(v,"delay"));easing_.push_back(Json::scalar(v,"easingType","InOut"));checkpointGroups_.push_back(Json::scalar(v,"spawnGroupID"));}}}void TriggerCameraMove::activateTrigger(TriggerSystem&s,FL_TriggerHost&h){h.triggerCameraMove(points_,durations_,delays_,easing_,dontReturnToPlayer_);for(size_t i=0;i<checkpointGroups_.size();++i)if(!checkpointGroups_[i].empty()&&checkpointGroups_[i]!="0")s.activateGroup(checkpointGroups_[i],GroupActivate,true,false,h);} }
